import AdminLayout from "../../AdminLayout";
import "./AddPatient.css";

export default function AddPatient() {
  return (
    <AdminLayout>
      <div className="page-bg">
        <div className="patient-card">

          <h2 className="page-title">Patient Registration</h2>

          {/* ================= Patient Information ================= */}
          <h3 className="section-title">Patient Information</h3>

          <div className="form-grid">

            <div className="full">
              <label>Medical Record Number (MRN)</label>
              <input type="text" placeholder="MRN123" />
            </div>

            {/* Photo */}
            <div className="photo-box">
              <div className="avatar"></div>
              <span>Upload Photo</span>
            </div>

            <div>
              <label>First Name</label>
              <input placeholder="John" />
            </div>

            <div>
              <label>Last Name</label>
              <input placeholder="Doe" />
            </div>

            <div>
              <label>Display Name</label>
              <input placeholder="John Doe" />
            </div>

            <div>
              <label>Date of Birth</label>
              <input type="date" />
            </div>

            <div>
              <label>Gender</label>
              <select>
                <option>Male</option>
                <option>Female</option>
              </select>
            </div>

            <div>
              <label>Marital Status</label>
              <select>
                <option>Single</option>
                <option>Married</option>
              </select>
            </div>

            <div>
              <label>Age</label>
              <input placeholder="45" />
            </div>

          </div>

          {/* ================= Contact Details ================= */}
          <h3 className="section-title">Contact Details</h3>

          <div className="form-grid four">

            <div>
              <label>Address</label>
              <input placeholder="123 Main St" />
            </div>

            <div>
              <label>City</label>
              <select>
                <option>Dubai</option>
              </select>
            </div>

            <div>
              <label>Country</label>
              <select>
                <option>UAE</option>
              </select>
            </div>

            <div>
              <label>Mobile Number</label>
              <input placeholder="+971 050124567" />
            </div>

          </div>

          {/* ================= Patient Identification ================= */}
          <h3 className="section-title">Patient Identification</h3>

          <div className="form-grid three">

            <div>
              <label>ID Type</label>
              <select>
                <option>Aadhar Card</option>
              </select>
            </div>

            <div>
              <label>ID Number</label>
              <input placeholder="1234 5678 9012" />
            </div>

            <div>
              <label>Expiry Date</label>
              <input type="date" />
            </div>

          </div>

          {/* ================= Emergency Contact ================= */}
          <h3 className="section-title">Emergency Contact</h3>

          <div className="form-grid three">

            <div>
              <label>First Name</label>
              <input placeholder="Jane" />
            </div>

            <div>
              <label>Last Name</label>
              <input placeholder="Doe" />
            </div>

            <div>
              <label>Mobile Number</label>
              <input placeholder="+971 0509876543" />
            </div>

          </div>

          <div className="actions">
            <button>Register Patient</button>
          </div>

        </div>
      </div>
    </AdminLayout>
  );
}
